try {
  const mockMedia = { volume: 0.5, playbackRate: 1.0, muted: false };
  const sandbox = new Function('mediaElement', 'options', code + '; return configureMedia;');
  const fn = sandbox();

  fn(mockMedia, { volume: 0.8, speed: 1.5, muted: true });
  if (mockMedia.volume !== 0.8) return 'volume to\'g\'ri o\'rnatilmadi';
  if (mockMedia.playbackRate !== 1.5) return 'playbackRate (speed) to\'g\'ri o\'rnatilmadi';
  if (mockMedia.muted !== true) return 'muted to\'g\'ri o\'rnatilmadi';

  try {
    fn(mockMedia, { volume: 1.5, speed: 1.0 });
    return '1.5 volume uchun RangeError otilishi kerak edi';
  } catch(err) {
    if (!(err instanceof RangeError)) return 'Noto\'g\'ri xatolik turi otildi. RangeError bo\'lishi shart.';
  }
} catch(e) {
  return 'Xato: ' + e.message;
}
return null;

